function formatRelativeDays(value?: string | null) {
  if (!value) return '创建时间未知'
  const time = new Date(value).getTime()
  if (!Number.isFinite(time)) return '创建时间未知'
  const days = Math.max(1, Math.floor((Date.now() - time) / (24 * 60 * 60 * 1000)))
  return `创建${days}天`
}

function formatPostTime(value?: string | null) {
  if (!value) return '刚刚'
  return new Date(value).toLocaleString('zh-CN', { hour12: false }).replace(/\//g, '-')
}

function buildPostBody(post: PostSummaryItem) {
  const text = post.contentText || post.summary || ''
  return text
    .split('\n')
    .map((item) => item.trim())
    .filter(Boolean)
    .slice(0, 4)
}

function formatCommentTime(value?: string | null) {
  if (!value) return ''
  return new Date(value).toLocaleString('zh-CN', { hour12: false }).replace(/\//g, '-')
}

