export function LoginPage() {
  const navigate = useNavigate()
  const location = useLocation()
  const redirectFrom = typeof (location.state as { from?: string } | null)?.from === 'string'
    ? (location.state as { from?: string }).from || '/'
    : '/'
  const [mobile, setMobile] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  useEffect(() => {
    let cancelled = false

    async function checkSession() {
      const session = await getCurrentSession()
      if (cancelled || !session) return

      navigate(redirectFrom, { replace: true })
    }

    void checkSession()

    return () => {
      cancelled = true
    }
  }, [navigate, redirectFrom])

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    setLoading(true)
    setError('')

    try {
      await loginWithMobile(mobile)
      navigate(redirectFrom, { replace: true })
    } catch (submitError) {
      if (submitError instanceof ApiError) {
        setError(submitError.message)
      } else {
        setError(submitError instanceof Error ? submitError.message : '登录失败，请稍后重试')
      }
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="auth-page">
      <form className="auth-card" onSubmit={handleSubmit}>
        <div className="auth-brand">
          <div className="auth-brand-logo">C</div>
          <div>
            <div className="auth-brand-name">知识星球</div>
            <div className="auth-brand-subtitle">admin-web 登录</div>
