        <label className="auth-field">
          <span>账号</span>
          <input
            autoComplete="tel"
            inputMode="numeric"
            maxLength={11}
            onChange={(event) => setMobile(normalizeMobile(event.target.value))}
            placeholder="请输入手机号"
            value={mobile}
          />
        </label>

        <button className="auth-submit" disabled={loading || mobile.length !== 11} type="submit">
          {loading ? '登录中...' : '登录'}
