  async refreshFeedContent(planetId: string) {
    if (!planetId) {
      return
    }

    try {
      const session = getStoredSession()
      const sessionToken = session && session.sessionToken ? session.sessionToken : ''
      const [latestResult, featuredResult, fileResult, answerResult, pinnedResult] = await Promise.allSettled([
        fetchPlanetPosts({ groupId: planetId, tab: 'latest', limit: 20, sessionToken }),
        fetchPlanetPosts({ groupId: planetId, tab: 'featured', limit: 20, sessionToken }),
        fetchPlanetPosts({ groupId: planetId, tab: 'files', limit: 20, sessionToken }),
        fetchPlanetPosts({ groupId: planetId, tab: 'answer', limit: 20, sessionToken }),
        fetchPinnedPosts(planetId, sessionToken),
      ])

      const latestResponse = getSettledValue(latestResult)
      const featuredResponse = getSettledValue(featuredResult)
      const fileResponse = getSettledValue(fileResult)
      const answerResponse = getSettledValue(answerResult)
      const pinnedResponse = getSettledValue(pinnedResult)

      const latestList =
        latestResponse && latestResponse.ok && latestResponse.data
          ? mapRemotePostsToFeedItems(latestResponse.data.items || [])
          : this.data.latestList
      const featuredList =
        featuredResponse && featuredResponse.ok && featuredResponse.data
          ? mapRemotePostsToFeedItems(featuredResponse.data.items || [])
          : this.data.featuredList
      const fileList =
        fileResponse && fileResponse.ok && fileResponse.data
          ? mapRemotePostsToFeedItems(fileResponse.data.items || [])
          : this.data.fileList
      const answerList =
        answerResponse && answerResponse.ok && answerResponse.data
          ? mapRemotePostsToFeedItems(answerResponse.data.items || [])
          : this.data.answerList
      const pinnedList =
        pinnedResponse && pinnedResponse.ok && Array.isArray(pinnedResponse.data)
          ? mapRemotePinnedPostsToItems(pinnedResponse.data)
          : this.data.pinnedList

      this.setData({
        latestList,
        featuredList,
        fileList,
        answerList,
        pinnedList,
        showNotices: !!pinnedList.length,
      })
    } catch {
      this.setData({
        latestList: [],
        featuredList: [],
        fileList: [],
        answerList: [],
        pinnedList: [],
        showNotices: false,
      })
    }
  },

  async ensurePlanetSession() {
    const session = getStoredSession()

    if (session && session.sessionToken) {
      return session
    }

    try {
      return await ensureWechatSession()
    } catch {
      return null
    }
  },

