import { getStoredSession } from '../../utils/auth'
import { fetchDiscoverFeaturedPosts, fetchDiscoverPlanets } from '../../utils/planet-api'
import { PlanetRemoteProfile, upsertRemotePlanets } from '../../utils/planet'
import { ensureWechatSession } from '../../utils/wechat-login'

interface InterestPlanetItem {
  id: string
  name: string
  meta: string
  summary: string
  image: string
  creator: string
}

interface FeaturedTopicItem {
  id: string
  postId: string
  planetId: string
  title: string
  summary: string
  author: string
  meta: string
  cover: string
}

const INTEREST_BATCH_SIZE = 3

const rotateBatch = <T>(list: T[], batchIndex: number, batchSize: number) => {
  if (list.length <= batchSize) {
    return list
  }

  const start = (batchIndex * batchSize) % list.length
  const result: T[] = []

  for (let offset = 0; offset < batchSize; offset += 1) {
    result.push(list[(start + offset) % list.length])
  }

  return result
}

const normalizeSummary = (summary: string, planetName: string) =>
  summary || `欢迎加入「${planetName}」，这里会持续分享精选内容、答疑和社群互动。`

const mapPlanetToInterestItem = (planet: PlanetRemoteProfile): InterestPlanetItem => ({
  id: planet.id,
  name: planet.name,
  meta: `主理人 ${planet.ownerName}`,
  summary: normalizeSummary(planet.intro || '', planet.name),
  image: planet.avatarImageUrl || planet.coverImageUrl,
  creator: planet.ownerName,
})

const mapRemoteFeaturedPost = (post: Record<string, any>): FeaturedTopicItem => {
  const group = post.group && typeof post.group === 'object' ? post.group : {}
  const title = String(post.title || '').trim()
  const summary = String(post.summary || post.contentText || '').trim()

  return {
    id: String(post.id || ''),
    postId: String(post.id || ''),
    planetId: String(post.groupId || group.id || ''),
    title: title || summary || '未命名精华主题',
    summary: summary || '这篇精华主题暂时还没有摘要',
    author:
      post.author && typeof post.author === 'object' && typeof post.author.nickname === 'string'
        ? post.author.nickname
        : '当前成员',
    meta: typeof group.name === 'string' && group.name ? group.name : '其他星球',
    cover: typeof post.coverUrl === 'string' ? post.coverUrl : '',
  }
}

Page({
  data: {
    loadingInterest: false,
    loadingFeatured: false,
    interestStatusText: '',
    featuredStatusText: '',
    interestSource: [] as InterestPlanetItem[],
    featuredSource: [] as FeaturedTopicItem[],
    interestList: [] as InterestPlanetItem[],
    featuredList: [] as FeaturedTopicItem[],
    interestBatchIndex: 0,
    featuredBatchIndex: 0,
  },

  onLoad() {
    void this.refreshContent(0, 0)
  },

  onShow() {
    void this.refreshContent(this.data.interestBatchIndex, this.data.featuredBatchIndex)
  },

  async ensurePlanetSession() {
    const session = getStoredSession()
    if (session && session.sessionToken) {
      return session
    }

    try {
      return await ensureWechatSession()
    } catch {
      return null
    }
  },

  async resolveInterestSource() {
    const session = await this.ensurePlanetSession()
    const response = await fetchDiscoverPlanets(session ? session.sessionToken : '', 12)

    if (!response.ok || !Array.isArray(response.data)) {
      return [] as InterestPlanetItem[]
    }

    const remotePlanets = response.data
      .filter((planet) => planet && planet.id && !planet.joined)
      .map((planet) => ({
        ...planet,
        joined: false,
      }))

    upsertRemotePlanets(remotePlanets, {
      defaultJoined: false,
    })

    return remotePlanets.map(mapPlanetToInterestItem)
  },

  async resolveFeaturedSource() {
    const session = await this.ensurePlanetSession()
    const response = await fetchDiscoverFeaturedPosts(12, session ? session.sessionToken : '')

    if (!response.ok || !Array.isArray(response.data)) {
      return [] as FeaturedTopicItem[]
    }

    return response.data
      .filter((item) => item && item.id && item.groupId)
      .map(mapRemoteFeaturedPost)
  },

  async refreshContent(nextInterestBatchIndex: number, nextFeaturedBatchIndex: number) {
    this.setData({
      loadingInterest: true,
      loadingFeatured: true,
      interestStatusText: '',
      featuredStatusText: '',
    })

    const [interestResult, featuredResult] = await Promise.allSettled([
      this.resolveInterestSource(),
      this.resolveFeaturedSource(),
    ])

    const interestSource =
      interestResult.status === 'fulfilled' ? interestResult.value : []
    const featuredSource =
      featuredResult.status === 'fulfilled' ? featuredResult.value : []

    const interestList = rotateBatch(interestSource, nextInterestBatchIndex, INTEREST_BATCH_SIZE)
    const featuredList = rotateBatch(featuredSource, nextFeaturedBatchIndex, 2)

    this.setData({
      loadingInterest: false,
      loadingFeatured: false,
      interestStatusText:
        interestResult.status === 'rejected'
          ? '真实星球数据拉取失败，请稍后重试'
          : interestSource.length
            ? ''
            : '还没有其他用户创建可推荐的真实星球',
      featuredStatusText:
        featuredResult.status === 'rejected'
          ? '真实精华主题拉取失败，请稍后重试'
          : featuredSource.length
            ? ''
            : '还没有可推荐的其他星球精华主题',
      interestSource,
      featuredSource,
      interestList,
      featuredList,
      interestBatchIndex: nextInterestBatchIndex,
      featuredBatchIndex: nextFeaturedBatchIndex,
    })
  },

  onRefreshInterest() {
    if (!this.data.interestSource.length) {
      void this.refreshContent(0, this.data.featuredBatchIndex)
      return
    }

    const nextInterestBatchIndex = this.data.interestBatchIndex + 1
    const interestList = rotateBatch(
      this.data.interestSource,
      nextInterestBatchIndex,
      INTEREST_BATCH_SIZE
    )

    this.setData({
      interestList,
      interestBatchIndex: nextInterestBatchIndex,
    })
  },

  onRefreshFeatured() {
    if (!this.data.featuredSource.length) {
      void this.refreshContent(this.data.interestBatchIndex, 0)
      return
    }

    const nextFeaturedBatchIndex = this.data.featuredBatchIndex + 1
    const featuredList = rotateBatch(this.data.featuredSource, nextFeaturedBatchIndex, 2)

    this.setData({
      featuredList,
      featuredBatchIndex: nextFeaturedBatchIndex,
    })
  },

  onPlanetTap(e: WechatMiniprogram.TouchEvent) {
    const id = e.currentTarget.dataset.id || 'planet_1'
    const name = e.currentTarget.dataset.name || 'Datawhale'
    const creator = e.currentTarget.dataset.creator || 'Datawhale 团队'

    wx.navigateTo({
      url: `/pages/planet/home?id=${id}&name=${encodeURIComponent(name)}&creator=${encodeURIComponent(creator)}&source=discover`,
    })
  },

  onTopicTap(e: WechatMiniprogram.TouchEvent) {
    const postId = String(e.currentTarget.dataset.postId || '')
    const planetId = String(e.currentTarget.dataset.planetId || '')

    if (!postId) {
      return
    }

    wx.navigateTo({
      url: `/pages/planet/post?id=${postId}&planetId=${planetId}`,
    })
  },

  onPlanetTabChange(e: WechatMiniprogram.CustomEvent<{ key: string }>) {
    const key = String((e.detail && e.detail.key) || '')

    if (!key || key === 'discover') {
      return
    }

    if (key === 'planet') {
      wx.redirectTo({
        url: '/pages/planet/index',
      })
      return
    }

    if (key === 'mine') {
      wx.redirectTo({
        url: '/pages/planet/mine',
      })
      return
    }

    if (key === 'debug') {
      wx.redirectTo({
        url: '/pages/planet/debug',
      })
    }
  },
})

import { getPlanetById } from '../../utils/planet'
import { getStoredSession } from '../../utils/auth'
import {
  createPlanetComment,
  fetchPlanetComments,
  fetchPlanetPostDetail,
  togglePlanetCommentLike,
  togglePlanetPostLike,
} from '../../utils/planet-api'

interface CommentView {
  id: string
  author: string
  time: string
  content: string
  likeCount: number
  liked: boolean
}

interface PostDetailView {
  id: string
  authorId: string
  displayAuthor: string
  avatar: string
  time: string
  title: string
  richContent: string
  tags: string[]
  images: string[]
  likeCount: number
  commentCount: number
  liked: boolean
  isRichContent: boolean
}

let currentPostId = ''
let currentPlanetId = 'grp_datawhale_001'
let skipNextOnShowRefresh = false

const legacyPlanetIdMap: Record<string, string> = {
  planet_1: 'grp_datawhale_001',
}

const resolvePlanetId = (planetId: string) => legacyPlanetIdMap[planetId] || planetId

const formatPostTime = (value?: string) => {
  if (!value) {
    return ''
  }

  const date = new Date(value)
  if (Number.isNaN(date.getTime())) {
    return value
  }

  const year = date.getFullYear()
  const month = `${date.getMonth() + 1}`.padStart(2, '0')
  const day = `${date.getDate()}`.padStart(2, '0')
  const hour = `${date.getHours()}`.padStart(2, '0')
  const minute = `${date.getMinutes()}`.padStart(2, '0')
  return `${year}/${month}/${day} ${hour}:${minute}`
}

const isImageUrl = (value: string) => /\.(png|jpe?g|gif|webp|bmp|svg)(\?.*)?$/i.test(value)

const createFallbackPost = (): PostDetailView => ({
  id: '',
  authorId: '',
  displayAuthor: '当前成员',
  avatar: '',
  time: '',
  title: '',
  richContent: '',
  tags: [],
  images: [],
  likeCount: 0,
  commentCount: 0,
  liked: false,
  isRichContent: false,
})

const extractImages = (post: Record<string, any>) => {
  const attachments = Array.isArray(post.attachments) ? post.attachments : []
  const attachmentImages = attachments
    .map((item) => {
      if (typeof item === 'string') {
        return item.trim()
      }
      if (item && typeof item === 'object' && typeof item.url === 'string') {
        return item.url.trim()
      }
      return ''
    })
    .filter((item) => /^https?:\/\//.test(item) && isImageUrl(item))

  const metadata = post.metadata && typeof post.metadata === 'object' ? post.metadata : {}
  const metadataImages = Array.isArray(metadata.images)
    ? metadata.images.filter(
        (item: unknown) => typeof item === 'string' && /^https?:\/\//.test(item) && isImageUrl(item)
      )
    : []

  return Array.from(new Set(attachmentImages.concat(metadataImages))).slice(0, 9)
}

const mapRemotePost = (post: Record<string, any>): PostDetailView => {
  const metadata = post.metadata && typeof post.metadata === 'object' ? post.metadata : {}
  const richContent = typeof metadata.richContent === 'string' ? metadata.richContent : ''
  const title = String(post.title || '').trim()

  return {
    id: String(post.id || ''),
    authorId:
      post.author && typeof post.author === 'object' && typeof post.author.id === 'string'
        ? post.author.id
        : '',
    displayAuthor:
      post.author && typeof post.author === 'object' && typeof post.author.nickname === 'string'
        ? post.author.nickname
        : '当前成员',
    avatar:
      post.author && typeof post.author === 'object' && typeof post.author.avatarUrl === 'string'
        ? post.author.avatarUrl
        : '',
    time: formatPostTime(post.publishedAt || post.createdAt || ''),
    title: title || String(post.contentText || '').trim(),
    richContent,
    tags: Array.isArray(metadata.tags) ? metadata.tags.filter((item: unknown) => typeof item === 'string') : [],
    images: extractImages(post),
    likeCount: Number(post.likeCount || 0),
    commentCount: Number(post.commentCount || 0),
    liked: !!post.viewerLiked,
    isRichContent: !!richContent,
  }
}

const mapRemoteComment = (comment: Record<string, any>): CommentView => ({
  id: String(comment.id || ''),
  author:
    comment.author && typeof comment.author === 'object' && typeof comment.author.nickname === 'string'
      ? comment.author.nickname
      : '当前成员',
  time: formatPostTime(comment.createdAt || ''),
  content: String(comment.content || '').trim(),
  likeCount: Number(comment.likeCount || 0),
  liked: !!comment.viewerLiked,
})

Page({
  data: {
    post: createFallbackPost(),
    commentInput: '',
    comments: [] as CommentView[],
    canLike: true,
    canEdit: false,
  },

  onLoad(options: Record<string, string>) {
    currentPostId = options.id || ''
    currentPlanetId = resolvePlanetId(options.planetId || 'grp_datawhale_001')
    skipNextOnShowRefresh = true
    void this.refreshPostDetail(true)
  },

  onShow() {
    if (skipNextOnShowRefresh) {
      skipNextOnShowRefresh = false
      return
    }

    void this.refreshPostDetail(false)
  },

  canCurrentUserEditPost(post: PostDetailView) {
    const session = getStoredSession()
    return !!(session && session.id && post.authorId && session.id === post.authorId)
  },

  async refreshPostDetail(incrementRead = false) {
    const postId = currentPostId
    if (!postId) {
      this.setData({
        post: createFallbackPost(),
        comments: [],
        canLike: false,
        canEdit: false,
      })
      return
    }

    try {
      const session = getStoredSession()
      const sessionToken = session && session.sessionToken ? session.sessionToken : ''
      const [postResponse, commentsResponse] = await Promise.all([
        fetchPlanetPostDetail(postId, incrementRead, sessionToken),
        fetchPlanetComments(postId, sessionToken),
      ])

      if (!postResponse.ok || !postResponse.data) {
        throw new Error('帖子不存在')
      }

      const post = mapRemotePost(postResponse.data)
      const comments =
        commentsResponse.ok && Array.isArray(commentsResponse.data)
          ? commentsResponse.data.map(mapRemoteComment)
          : []

      this.setData({
        post,
        comments,
        canLike: true,
        canEdit: this.canCurrentUserEditPost(post),
      })
    } catch (error) {
      this.setData({
        post: createFallbackPost(),
        comments: [],
        canLike: false,
        canEdit: false,
      })

      wx.showToast({
        title: error instanceof Error ? error.message : '帖子加载失败',
        icon: 'none',
      })
    }
  },

  onCommentInput(e: WechatMiniprogram.Input) {
    this.setData({
      commentInput: e.detail.value,
    })
  },

  async onCommentConfirm() {
    const content = this.data.commentInput.trim()
    const postId = this.data.post.id
    const session = getStoredSession()

    if (!postId) {
      wx.showToast({
        title: '当前文章不可评论',
        icon: 'none',
      })
      return
    }

    if (!content) {
      wx.showToast({
        title: '请输入观点内容',
        icon: 'none',
      })
      return
    }

    if (!session || !session.id || !session.sessionToken) {
      wx.showToast({
        title: '请先登录',
        icon: 'none',
      })
      return
    }

    try {
      const response = await createPlanetComment({
        postId,
        userId: session.id,
        content,
        sessionToken: session.sessionToken,
      })

      if (!response.ok) {
        throw new Error('评论失败')
      }

      this.setData({
        commentInput: '',
      })
      await this.refreshPostDetail()

      wx.showToast({
        title: '观点已发布',
        icon: 'success',
      })
    } catch (error) {
      wx.showToast({
        title: error instanceof Error ? error.message : '评论失败',
        icon: 'none',
      })
    }
  },

  async onLikeTap() {
    const postId = this.data.post.id
    const session = getStoredSession()
    if (!postId) {
      wx.showToast({
        title: '当前文章不可点赞',
        icon: 'none',
      })
      return
    }

    if (!session || !session.sessionToken) {
      wx.showToast({
        title: '请先登录',
        icon: 'none',
      })
      return
    }

    try {
      const response = await togglePlanetPostLike({
        postId,
        increment: !this.data.post.liked,
        sessionToken: session.sessionToken,
      })

      if (!response.ok || !response.data) {
        throw new Error('点赞失败')
      }

      const nextPost = mapRemotePost(response.data)
      nextPost.liked = !!response.data.viewerLiked
      this.setData({
        post: nextPost,
      })
    } catch (error) {
      wx.showToast({
        title: error instanceof Error ? error.message : '点赞失败，请稍后重试',
        icon: 'none',
      })
    }
  },

  async onCommentLikeTap(e: WechatMiniprogram.TouchEvent) {
    const commentId = String(e.currentTarget.dataset.id || '')
    const session = getStoredSession()

    if (!commentId) {
      return
    }

    if (!session || !session.sessionToken) {
      wx.showToast({
        title: '请先登录',
        icon: 'none',
      })
      return
    }

    const targetComment = this.data.comments.find((item) => item.id === commentId)
    if (!targetComment) {
      return
    }

    try {
      const response = await togglePlanetCommentLike({
        commentId,
        increment: !targetComment.liked,
        sessionToken: session.sessionToken,
      })

      if (!response.ok || !response.data) {
        throw new Error('评论点赞失败')
      }

      const nextComments = this.data.comments.map((item) =>
        item.id === commentId
          ? {
              ...item,
              likeCount: Number(response.data.likeCount || 0),
              liked: !!response.data.viewerLiked,
            }
          : item
      )

      this.setData({
        comments: nextComments,
      })
    } catch (error) {
      wx.showToast({
        title: error instanceof Error ? error.message : '评论点赞失败',
        icon: 'none',
      })
    }
  },

  onGeneratePoster() {
    const postId = this.data.post.id
    if (!postId) {
      wx.showToast({
        title: '当前文章不可生成长图',
        icon: 'none',
      })
      return
    }

    wx.navigateTo({
      url: `/pages/planet/poster?id=${postId}&planetId=${currentPlanetId}`,
    })
  },

  onEditPost() {
    const postId = this.data.post.id
    if (!postId || !this.data.canEdit) {
      wx.showToast({
        title: '当前帖子不可编辑',
        icon: 'none',
      })
      return
    }

    wx.navigateTo({
      url: `/pages/planet-publish/index?planetId=${currentPlanetId}&planetName=${encodeURIComponent((getPlanetById(currentPlanetId) || { name: '知识星球' }).name)}&postId=${postId}`,
    })
  },

  onShareAppMessage() {
    const { post } = this.data
    const shareTitle = post.title.length > 26 ? `${post.title.slice(0, 26)}...` : post.title

    return {
      title: shareTitle || '文章详情',
      path: `/pages/planet/post?id=${post.id}`,
      imageUrl: post.images[0] || '',
    }
  },

  onShareTimeline() {
    const { post } = this.data
    const shareTitle = post.title.length > 26 ? `${post.title.slice(0, 26)}...` : post.title

    return {
      title: shareTitle || '文章详情',
      query: `id=${post.id}`,
      imageUrl: post.images[0] || '',
    }
  },
})

import { getStoredSession, saveSession, type UserSession } from './auth'
import { loginByPhoneNumber, loginByWechat } from './auth-api'

let loginTask: Promise<UserSession> | null = null

function createRequestId() {
  return `plogin_${Date.now()}_${Math.random().toString(16).slice(2, 10)}`
}

function runWxLogin() {
  return new Promise<WechatMiniprogram.LoginSuccessCallbackResult>((resolve, reject) => {
    wx.login({
      success: resolve,
      fail: reject,
    })
  })
}

function applySession(session: UserSession) {
  saveSession(session)

  const app = getApp<IAppOption>()
  app.globalData.userSession = session
}

export function getCurrentSession() {
  return getStoredSession()
}

export async function ensureWechatSession(forceRefresh = false) {
  const storedSession = getStoredSession()

  if (!forceRefresh && storedSession && storedSession.sessionToken) {
    applySession(storedSession)
    return storedSession
  }

  if (loginTask) {
    return loginTask
  }

  loginTask = (async () => {
    const loginResult = await runWxLogin()
    const response = await loginByWechat({
      loginCode: loginResult.code || '',
    })
    const session = response.data

    applySession(session)
    return session
  })()

  try {
    return await loginTask
  } finally {
    loginTask = null
  }
}

export async function loginWithPhoneCode(phoneCode: string) {
  const loginResult = await runWxLogin()
  const response = await loginByPhoneNumber({
    loginCode: loginResult.code || '',
    phoneCode,
    requestId: createRequestId(),
  })
  const session = response.data

  applySession(session)
  return session
}

import { loadPlanets, PlanetProfile, upsertRemotePlanets } from '../../utils/planet'
import { getStoredSession } from '../../utils/auth'
import { fetchJoinedPlanets, fetchMyPlanets } from '../../utils/planet-api'
import { ensureWechatSession } from '../../utils/wechat-login'

const filterPlanets = (planets: PlanetProfile[], keyword: string) => {
  if (!keyword) {
    return planets
  }

  return planets.filter((planet) => planet.name.toLowerCase().includes(keyword))
}

Page({
  data: {
    searchValue: '',
    joinedPlanetIds: [] as string[],
    myPlanetIds: [] as string[],
    allPlanets: [] as PlanetProfile[],
    joinedPlanets: [] as PlanetProfile[],
    userPlanets: [] as PlanetProfile[],
    searchResults: [] as PlanetProfile[],
  },

  onLoad() {
    this.refreshPlanets()
    void this.syncPlanetsFromServer()
  },

  onShow() {
    this.refreshPlanets()
    void this.syncPlanetsFromServer()
  },

  async ensurePlanetSession() {
    const session = getStoredSession()
    if (session && session.sessionToken) {
      return session
    }

    try {
      return await ensureWechatSession()
    } catch {
      // 知识星球首页不阻塞主流程，静默登录失败时由“我的”页兜底重试
      return null
    }
  },

  async syncPlanetsFromServer() {
    const session = await this.ensurePlanetSession()

    if (!session || !session.sessionToken) {
      this.setData({
        joinedPlanetIds: [],
        myPlanetIds: [],
      })
      this.refreshPlanets()
      return
    }

    try {
      const [joinedResponse, myResponse] = await Promise.all([
        fetchJoinedPlanets(session.sessionToken),
        fetchMyPlanets(session.sessionToken),
      ])

      if (
        !joinedResponse.ok ||
        !Array.isArray(joinedResponse.data) ||
        !myResponse.ok ||
        !Array.isArray(myResponse.data)
      ) {
        return
      }

      const joinedPlanetIds = joinedResponse.data.map((planet) => planet.id)
      const myPlanetIds = myResponse.data.map((planet) => planet.id)

      upsertRemotePlanets(
        joinedResponse.data.map((planet) => ({
          ...planet,
          joined: true,
        }))
      )
      upsertRemotePlanets(
        myResponse.data.map((planet) => ({
          ...planet,
          joined: true,
        }))
      )
      this.setData({
        joinedPlanetIds,
        myPlanetIds,
      })
      this.refreshPlanets()
    } catch {
      // 星球首页优先保证可用，接口失败时保留本地缓存展示
    }
  },

  refreshPlanets() {
    const localPlanets = loadPlanets()
    const joinedPlanetIdSet = new Set(this.data.joinedPlanetIds)
    const myPlanetIdSet = new Set(this.data.myPlanetIds)
    const joinedPlanets = localPlanets.filter((planet) => joinedPlanetIdSet.has(planet.id))
    const userPlanets = localPlanets.filter((planet) => myPlanetIdSet.has(planet.id))
    const visiblePlanets = [...joinedPlanets]

    userPlanets.forEach((planet) => {
      if (!visiblePlanets.some((item) => item.id === planet.id)) {
        visiblePlanets.push(planet)
      }
    })

    const keyword = this.data.searchValue.trim().toLowerCase()
    const searchResults = filterPlanets(visiblePlanets, keyword)

    this.setData({
      allPlanets: visiblePlanets,
      joinedPlanets,
      userPlanets,
      searchResults,
    })
  },

  onSearchInput(e: WechatMiniprogram.Input) {
    const searchValue = e.detail.value
    const keyword = searchValue.trim().toLowerCase()
    const searchResults = filterPlanets(this.data.allPlanets, keyword)

    this.setData({
      searchValue,
      searchResults,
    })
  },

  onPlanetTap(e: WechatMiniprogram.TouchEvent) {
    const id = e.currentTarget.dataset.id || 'planet_1'
    const name = e.currentTarget.dataset.name || 'Datawhale'
    const creator = e.currentTarget.dataset.creator || 'Datawhale 团队'
    const joined = !!e.currentTarget.dataset.joined
    const source = joined ? 'joined' : 'discover'

    wx.navigateTo({
      url: `/pages/planet/home?id=${id}&name=${encodeURIComponent(name)}&creator=${encodeURIComponent(creator)}&source=${source}`,
    })
  },

  onPlanetTabChange(e: WechatMiniprogram.CustomEvent<{ key: string }>) {
    const key = String((e.detail && e.detail.key) || '')

    if (!key || key === 'planet') {
      return
    }

    if (key === 'discover') {
      wx.redirectTo({
        url: '/pages/planet/lobby',
      })
      return
    }

    if (key === 'mine') {
      wx.redirectTo({
        url: '/pages/planet/mine',
      })
      return
    }

    if (key === 'debug') {
      wx.redirectTo({
        url: '/pages/planet/debug',
      })
    }
  },

  goCreate() {
    wx.navigateTo({
      url: '/pages/planet/create',
    })
  },
})

import { getPlanetById } from '../../utils/planet'
import { getStoredSession } from '../../utils/auth'
import { createPlanetPost, fetchPlanetPostDetail, updatePlanetPost, uploadPlanetImage } from '../../utils/planet-api'

const PLANET_PUBLISH_REFRESH_KEY = 'planet_publish_refresh_v1'
const legacyPlanetIdMap: Record<string, string> = {
  planet_1: 'grp_datawhale_001',
}

interface EditorStatusPayload {
  bold?: boolean
  italic?: boolean
  underline?: boolean
  header?: string
  list?: string
}

interface PublishPageData {
  planetId: string
  planetName: string
  postId: string
  isEditMode: boolean
  title: string
  tagInput: string
  imagePreviewList: string[]
  editorReady: boolean
  editorHtml: string
  editorText: string
  toolbarStatus: {
    bold: boolean
    italic: boolean
    underline: boolean
    heading: boolean
    bulletList: boolean
  }
  submitting: boolean
  uploadingImages: boolean
}

type EditorContext = WechatMiniprogram.EditorContext
type PublishPageInstance = WechatMiniprogram.Page.Instance<PublishPageData> & {
  syncEditorContent: () => Promise<{ html: string; text: string } | null>
}

const MAX_TITLE_LENGTH = 40
const MAX_TEXT_LENGTH = 5000

let editorCtx: EditorContext | null = null
let pendingEditorHtml = ''

const resolvePlanetId = (planetId: string) => legacyPlanetIdMap[planetId] || planetId

const escapeHtml = (value: string) =>
  value
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')

const escapeRegExp = (value: string) => value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')

const stripHtml = (html: string) =>
  html
    .replace(/<img[^>]*>/gi, ' [图片] ')
    .replace(/<\/(p|div|li|h1|h2|h3|blockquote)>/gi, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim()

const extractImageUrls = (html: string) => {
  const matched = html.match(/<img[^>]+src=["']([^"']+)["'][^>]*>/gi) || []
  const urls = matched
    .map((item) => {
      const srcMatch = item.match(/src=["']([^"']+)["']/i)
      return srcMatch ? srcMatch[1] : ''
    })
    .filter((item) => /^https?:\/\//.test(item))

  return Array.from(new Set(urls)).slice(0, 9)
}

const buildSummary = (title: string, text: string) => {
  const normalizedText = text.replace(/\s+/g, ' ').trim()
  if (title && normalizedText) {
    return `${title} ${normalizedText}`.slice(0, 120)
  }
  return (title || normalizedText).slice(0, 120)
}

const toEditorHtml = (value: string) => {
  const content = String(value || '').trim()
  if (!content) {
    return ''
  }

  if (/<[a-z][\s\S]*>/i.test(content)) {
    return content
  }

  return content
    .split(/\n+/)
    .map((item) => `<p>${escapeHtml(item)}</p>`)
    .join('')
}

const stripLeadingTitleFromHtml = (html: string, title: string) => {
  const normalizedTitle = title.trim()
  if (!normalizedTitle || !html) {
    return html
  }

  const headingPattern = new RegExp(
    `^\\s*<(h1|h2|h3|p|div)[^>]*>\\s*${escapeRegExp(escapeHtml(normalizedTitle))}\\s*<\\/\\1>\\s*`,
    'i'
  )
  return html.replace(headingPattern, '').trim()
}

const stripImageTags = (html: string) => html.replace(/<img[^>]*>/gi, '').trim()

const extractImageUrlsFromPost = (post: Record<string, any>, richContent: string) => {
  const attachmentImages = Array.isArray(post.attachments)
    ? post.attachments.filter((item: unknown) => typeof item === 'string' && /^https?:\/\//.test(item))
    : []
  const richImages = extractImageUrls(richContent)
  return Array.from(new Set(attachmentImages.concat(richImages))).slice(0, 9)
}

const parseRemotePostDraft = (post: Record<string, any>) => {
  const metadata = post.metadata && typeof post.metadata === 'object' ? post.metadata : {}
  const title = typeof post.title === 'string' ? post.title : ''
  const richContent = typeof metadata.richContent === 'string' ? metadata.richContent : ''
  const cleanedHtml = stripImageTags(stripLeadingTitleFromHtml(richContent || toEditorHtml(String(post.contentText || '')), title))

  return {
    title: title.slice(0, MAX_TITLE_LENGTH),
    editorHtml: cleanedHtml,
    tags: Array.isArray(metadata.tags) ? metadata.tags.filter((item: unknown) => typeof item === 'string') : [],
    images: extractImageUrlsFromPost(post, richContent),
  }
}

const applyEditorHtml = (page: PublishPageInstance, html: string) => {
  pendingEditorHtml = html
  if (!editorCtx) {
    return
  }

  editorCtx.setContents({
    html,
    success: () => {
      void page.syncEditorContent()
    },
  })
}

Page<PublishPageData>({
  data: {
    planetId: 'grp_datawhale_001',
    planetName: '知识星球',
    postId: '',
    isEditMode: false,
    title: '',
    tagInput: '',
    imagePreviewList: [],
    editorReady: false,
    editorHtml: '',
    editorText: '',
    toolbarStatus: {
      bold: false,
      italic: false,
      underline: false,
      heading: false,
      bulletList: false,
    },
    submitting: false,
    uploadingImages: false,
  },

  async onLoad(options: Record<string, string>) {
    editorCtx = null
    pendingEditorHtml = ''

    const planetId = resolvePlanetId(options.planetId || 'grp_datawhale_001')
    const postId = options.postId || ''
    const currentPlanet = getPlanetById(planetId)
    const planetName =
      options.planetName
        ? decodeURIComponent(options.planetName)
        : currentPlanet && currentPlanet.name
          ? currentPlanet.name
          : '知识星球'

    this.setData({
      planetId,
      planetName,
      postId,
      isEditMode: !!postId,
    })

    if (!postId) {
      return
    }

    try {
      const session = getStoredSession()
      const response = await fetchPlanetPostDetail(postId, false, session && session.sessionToken ? session.sessionToken : '')
      if (!response.ok || !response.data) {
        throw new Error('原帖子不存在')
      }

      const draft = parseRemotePostDraft(response.data)
      applyEditorHtml(this, draft.editorHtml)

      this.setData({
        title: draft.title,
        tagInput: draft.tags.join(', '),
        imagePreviewList: draft.images,
        editorHtml: draft.editorHtml,
        editorText: stripHtml(draft.editorHtml),
      })
    } catch (error) {
      wx.showToast({
        title: error instanceof Error ? error.message : '读取帖子失败',
        icon: 'none',
      })
    }
  },

  onUnload() {
    editorCtx = null
  },

  onTitleInput(e: WechatMiniprogram.Input) {
    this.setData({
      title: e.detail.value.slice(0, MAX_TITLE_LENGTH),
    })
  },

  onTagInput(e: WechatMiniprogram.Input) {
    this.setData({
      tagInput: e.detail.value.slice(0, 60),
    })
  },

  onEditorReady() {
    wx.createSelectorQuery()
      .in(this)
      .select('#planet-editor')
      .context((res) => {
        const context = res && 'context' in res ? (res.context as EditorContext) : null
        editorCtx = context

        this.setData({
          editorReady: !!context,
        })

        if (context && pendingEditorHtml) {
          applyEditorHtml(this, pendingEditorHtml)
        }
      })
      .exec()
  },

  onEditorInput() {
    void this.syncEditorContent()
  },

  onEditorStatusChange(e: WechatMiniprogram.CustomEvent<EditorStatusPayload>) {
    const status = e.detail || {}

    this.setData({
      toolbarStatus: {
        bold: !!status.bold,
        italic: !!status.italic,
        underline: !!status.underline,
        heading: String(status.header || '').toUpperCase() === 'H2',
        bulletList: status.list === 'bullet',
      },
    })
  },

  async syncEditorContent() {
    if (!editorCtx) {
      return null
    }

    return new Promise<{ html: string; text: string } | null>((resolve) => {
      editorCtx!.getContents({
        success: (res) => {
          const html = (res && res.html ? res.html : '').trim()
          const text = (res && res.text ? res.text : '').trim().slice(0, MAX_TEXT_LENGTH)

          this.setData({
            editorHtml: html,
            editorText: text,
          })

          resolve({
            html,
            text,
          })
        },
        fail: () => resolve(null),
      })
    })
  },

  execFormat(command: string, value?: string) {
    if (!editorCtx) {
      wx.showToast({
        title: '编辑器还没准备好',
        icon: 'none',
      })
      return
    }

    editorCtx.focus()
    editorCtx.format(command, value)
  },

  onToolbarTap(e: WechatMiniprogram.TouchEvent) {
    const command = String(e.currentTarget.dataset.command || '')
    const value = e.currentTarget.dataset.value

    if (!command || !editorCtx) {
      return
    }

    if (command === 'clear') {
      editorCtx.clear({
        success: () => {
          this.setData({
            editorHtml: '',
            editorText: '',
            toolbarStatus: {
              bold: false,
              italic: false,
              underline: false,
              heading: false,
              bulletList: false,
            },
          })
        },
      })
      return
    }

    if (command === 'insertDivider') {
      editorCtx.insertDivider({})
      return
    }

    if (command === 'removeFormat') {
      editorCtx.removeFormat({})
      return
    }

    this.execFormat(command, typeof value === 'string' ? value : undefined)
  },

  async onChooseImages() {
    const session = getStoredSession()
    if (!session || !session.sessionToken) {
      wx.showToast({
        title: '请先登录',
        icon: 'none',
      })
      return
    }

    const remainCount = Math.max(0, 9 - this.data.imagePreviewList.length)
    if (!remainCount) {
      wx.showToast({
        title: '最多上传9张图片',
        icon: 'none',
      })
      return
    }

    try {
      const chooseResult = await new Promise<WechatMiniprogram.ChooseMediaSuccessCallbackResult>((resolve, reject) => {
        wx.chooseMedia({
          count: remainCount,
          mediaType: ['image'],
          sizeType: ['compressed'],
          sourceType: ['album', 'camera'],
          success: resolve,
          fail: reject,
        })
      })

      const files = Array.isArray(chooseResult.tempFiles) ? chooseResult.tempFiles : []
      if (!files.length) {
        return
      }

      this.setData({
        uploadingImages: true,
      })

      wx.showLoading({
        title: '上传图片中',
        mask: true,
      })

      const uploadedUrls: string[] = []
      for (const file of files) {
        if (!file.tempFilePath) {
          continue
        }

        const response = await uploadPlanetImage(file.tempFilePath, session.sessionToken)
        if (!response.ok || !response.data || !response.data.url) {
          throw new Error('图片上传失败')
        }
        uploadedUrls.push(response.data.url)
      }

      const imagePreviewList = Array.from(new Set(this.data.imagePreviewList.concat(uploadedUrls))).slice(0, 9)
      this.setData({
        imagePreviewList,
      })
    } catch (error) {
      wx.showToast({
        title: error instanceof Error ? error.message : '图片上传失败',
        icon: 'none',
      })
    } finally {
      wx.hideLoading()
      this.setData({
        uploadingImages: false,
      })
    }
  },

  onRemoveImage(e: WechatMiniprogram.TouchEvent) {
    const index = Number(e.currentTarget.dataset.index)
    if (!Number.isFinite(index) || index < 0) {
      return
    }

    const nextList = this.data.imagePreviewList.filter((_, currentIndex) => currentIndex !== index)
    this.setData({
      imagePreviewList: nextList,
    })
  },

  async onSubmit() {
    if (this.data.submitting) {
      return
    }

    const session = getStoredSession()
    if (!session || !session.id || !session.sessionToken) {
      wx.showToast({
        title: '请先登录',
        icon: 'none',
      })
      return
    }

    const editorContent = await this.syncEditorContent()
    const title = this.data.title.trim()
    const editorHtml = editorContent ? editorContent.html : this.data.editorHtml
    const editorText = editorContent ? editorContent.text : this.data.editorText
    const normalizedText = stripHtml(editorHtml || editorText)

    if (!normalizedText) {
      wx.showToast({
        title: '请先填写正文内容',
        icon: 'none',
      })
      return
    }

    const tags = this.data.tagInput
      .split(/[\s,，]+/)
      .map((item) => item.trim())
      .filter(Boolean)
      .slice(0, 4)
    const nextImages = this.data.imagePreviewList
    const summary = buildSummary(title, normalizedText)
    const richContent = editorHtml

    this.setData({
      submitting: true,
    })

    try {
      const payload = {
        postId: this.data.postId,
        groupId: this.data.planetId,
        userId: session.id,
        sessionToken: session.sessionToken,
        title,
        summary,
        contentText: normalizedText,
        attachments: nextImages,
        metadata: {
          tags,
          richContent,
          images: nextImages,
        },
      }

      const response = this.data.isEditMode && this.data.postId ? await updatePlanetPost(payload) : await createPlanetPost(payload)

      if (!response.ok) {
        throw new Error(this.data.isEditMode ? '修改失败' : '发布失败')
      }

      wx.setStorageSync(PLANET_PUBLISH_REFRESH_KEY, this.data.planetId)

      wx.showToast({
        title: this.data.isEditMode ? '修改成功' : '发布成功',
        icon: 'success',
      })

      setTimeout(() => {
        const pages = getCurrentPages()
        if (pages.length > 1) {
          wx.navigateBack({
            delta: 1,
          })
          return
        }

        wx.redirectTo({
          url: `/pages/planet/home?id=${this.data.planetId}&name=${encodeURIComponent(this.data.planetName)}&source=joined`,
        })
      }, 280)
    } catch (error) {
      wx.showToast({
        title: error instanceof Error ? error.message : '发布失败，请稍后再试',
        icon: 'none',
      })
    } finally {
      setTimeout(() => {
        this.setData({
          submitting: false,
        })
      }, 300)
    }
  },
})

