          wx.switchTab({
            url: backUrl,
          })
        } else {
          wx.redirectTo({
            url: backUrl,
          })
        }
        this.triggerEvent('back', { delta: data.delta, backUrl }, {})
        return
      }

      if (data.delta) {
        wx.navigateBack({
          delta: data.delta,
        })
      }
      this.triggerEvent('back', { delta: data.delta }, {})
    },
    home() {
      wx.switchTab({
        url: '/pages/index/index',
      })
      this.triggerEvent('home', {}, {})
    },
  },
})

